ass":"NSArray"},"text":"负载降级","shrink":true},"3":{"objectClass":"MindNode","ID":"VVEDJ","children":{"0":{"objectClass":"MindNode","ID":"XGJEI","text":"令牌桶算法"},"objectClass":"NSArray"},"text":"算法"},"objectClass":"NSArray"},"text":"限流","shrink":true},"objectClass":"NSArray"},"text":"限流&熔断&降级"},"2":{"objectClass":"MindNode","ID":"1JKNG","text":"强弱依赖分析"},"3":{"objectClass":"MindNode","ID":"TI404","text":"参数&签名校验"},"objectClass":"NSArray"},"text":"方案"},"objectClass":"NSArray"},"text":"RPC相关","shrink":true},"4":{"objectClass":"MindNode","ID":"0317T","children":{"0":{"objectClass":"MindNode","ID":"LSS55","children":{"0":{"objectClass":"MindNode","ID":"2PN2V","text":"中间件难升级"},"1":{"objectClass":"MindNode","ID":"89VEB","text":"配置动态刷新"},"objectClass":"NSArray"},"text":"问题"},"1":{"objectClass":"MindNode","ID":"50KP0","children":{"0":{"objectClass":"MindNode","ID":"3F3FK","text":"Service Mesh"},"1":{"objectClass":"MindNode","ID":"R26DM","text":"分布式链路追踪"},"2":{"objectClass":"MindNode","ID":"31Q37","text":"静态扫描工具"},"objectClass":"NSArray"},"text":"方案"},"objectClass":"NSArray"},"text":"框架相关","shrink":true},"5":{"objectClass":"MindNode","ID":"6RJ10","children":{"0":{"objectClass":"MindNode","ID":"JTRAA","children":{"0":{"objectClass":"MindNode","ID":"0CU71","text":"稳定性诉求强烈"},"objectClass":"NSArray"},"text":"问题"},"1":{"objectClass":"MindNode","ID":"GFD4D","children":{"0":{"objectClass":"MindNode","ID":"04HNY","text":"同城容灾","summaries":{"0":{"objectClass":"NodeSummary","ID":"37LXS","text":"业务流量在同一个可用区内流转","offset":{"objectClass":"CGPoint","x":0,"y":0}},"objectClass":"NSArray"}},"1":{"objectClass":"MindNode","ID":"37LXS","text":"异地多活"},"2":{"objectClass":"MindNode","ID":"Y3929","text":"紧急预案","style2":{"objectClass":"NSDictionary","bold":0}},"3":{"objectClass":"MindNode","ID":"SMMWM","text":"日常演练"},"objectClass":"NSArray"},"text":"方案"},"objectClass":"NSArray"},"text":"容灾相关","shrink":true},"objectClass":"NSArray"},"text":"微服务治理的困境"},"2":{"objectClass":"MindNode","ID":"3LLU6","children":{"0":{"objectClass":"MindNode","ID":"G1LA7","text":"重构系统和重构代码一样，首先要先识别系统的坏味道。"},"1":{"objectClass":"MindNode","ID":"71UZG","children":{"0":{"objectClass":"MindNode","ID":"I256M","children":{"0":{"objectClass":"MindNode","ID":"M7X67","children":{"0":{"objectClass":"MindNode","ID":"80LD3","children":{"0":{"objectClass":"MindNode","ID":"Z3L51","text":"实际上逐渐演变成一个分布式大单体。"},"objectClass":"NSArray"},"text":"耦合性非常强，服务很难做到独立部署。"},"1":{"objectClass":"MindNode","ID":"1NL7T","text":"很可能导致一些循环调用或并发问题。"},"objectClass":"NSArray"},"text":"危害"},"1":{"objectClass":"MindNode","ID":"5N816","children":{"0":{"objectClass":"MindNode","ID":"N8CT8","children":{"0":{"objectClass":"MindNode","ID":"5N626","children":{"0":{"objectClass":"MindNode","ID":"90RZG","text":"为了保证多个服务之间数据的一致性，某个服务对数据的修改要同步到其他服务，保证其他服务冗余字段的信息准确。"},"objectClass":"NSArray"},"text":"数据冗余是导致服务之间循环依赖的主要原因。"},"objectClass":"NSArray"},"text":"数据过度冗余"},"1":{"objectClass":"MindNode","ID":"MD6K6","children":{"0":{"objectClass":"MindNode","ID":"6LCNE","children":{"0":{"objectClass":"MindNode","ID":"Z31K6","text":"典型的场景是上游系统的数据状态需要下游系统的数据进行计算得到，当需要上游系统的数据状态时，上游服务会调用下游服务的接口来进行计算。"},"objectClass":"NSArray"},"text":"和数据过度冗余相对的是在软件设计时缺少必要的业务概念。"},"objectClass":"NSArray"},"text":"缺失业务概念"},"2":{"objectClass":"MindNode","ID":"464IG","children":{"0":{"objectClass":"MindNode","ID":"PQJ14","children":{"0":{"objectClass":"MindNode","ID":"778P7","text":"长远来看，这种无脑的滥用同步调用让系统的复杂度变的非常高，当我们希望替换或重构某个服务，我们很难依据业务分析清楚到底有哪些服务会受到影响。"},"objectClass":"NSArray"},"text":"用户离职更新客户所有者信息的场景就是一个很好的例子。"},"objectClass":"NSArray"},"text":"滥用同步调用"},"objectClass":"NSArray"},"text":"原因"},"2":{"objectClass":"MindNode","ID":"3UU81","children":{"0":{"objectClass":"MindNode","ID":"Z8E0Y","children":{"0":{"objectClass":"MindNode","ID":"8LY6V","text":"定义服务上下游关系，下游服务可以直接依赖上游服务，反之则不可。"},"1":{"objectClass":"MindNode","ID":"TP2SP","text":"上游服务的变更对下游服务产生影响需要通过领域事件（异步）的方式来实现。"},"2":{"objectClass":"MindNode","ID":"3CXR2","text":"服务之间要通过数据 Id（能够唯一代表数据且不变的属性）来进行关联，尽量不做过多的数据冗余。"},"3":{"objectClass":"MindNode","ID":"O81QH","text":"一旦需要上游服务调用下游服务才能完成业务时，要考虑是否上游服务缺少业务概念。"},"4":{"objectClass":"MindNode","ID":"7BXCV","text":"为满足前端逻辑而导致的服务间交互逻辑要放到 BFF（Backend for frontend）中，而不是增加服务间的调用。"},"objectClass":"NSArray"},"text":"要解决循环依赖，必须要在微服务之间建立一些原则来约束微服务之间的通信，定期通过这些原则来审视我们的系统，找到问题并进行重构，这些原则应该包括："},"objectClass":"NSArray"},"text":"解决方案"},"3":{"objectClass":"MindNode","ID":"8FIK0","children":{"0":{"objectClass":"MindNode","ID":"RN22R","text":"通过链路追踪系统（如 Zipkin）将服务间依赖关系可视化出来。","summaries":{"0":{"objectClass":"NodeSummary","ID":"E5J74","text":"可视化的方式可以很容易帮我们找到系统中循环依赖的问题，然后我们就可以对症下药，消灭坏味道。","offset":{"objectClass":"CGPoint","x":0,"y":0}},"objectClass":"NSArray"}},"1":{"objectClass":"MindNode","ID":"E5J74","text":"在发现问题时将有问题的流程时序图画出来。"},"objectClass":"NSArray"},"text":"发现手段"},"objectClass":"NSArray"},"text":"循环依赖","shrink":true,"remark":"https://xie.infoq.cn/article/fd415110fbefe11b12b1d127f","remarkDisplay":true},"1":{"objectClass":"MindNode","ID":"8GJ72","children":{"0":{"objectClass":"MindNode","ID":"QG12F","text":"共享库在微服务之间建立了一个隐藏的耦合关系，当一个服务需要对共享库进行升级时，很难确定修改是否会对其他服务产生影响，这无疑增加了微服务开发团队之间的沟通成本。"},"1":{"objectClass":"MindNode","ID":"B57QV","text":"在微服务比较多的情况下，大而全的共享库版本的管理是非常困难的。"},"2":{"objectClass":"MindNode","ID":"O5183","children":{"0":{"objectClass":"MindNode","ID":"L7M4Q","children":{"0":{"objectClass":"MindNode","ID":"JB2IZ","text":"对于功能稳定通用且和业务本身无关的代码，推荐以职责单一的共享库的形式存在，比如日志、权限控制等分别以单独的日志库和权限库的形式存在，各个微服务按需添加依赖即可。"},"objectClass":"NSArray"},"text":"职责单一的基础架构库"},"1":{"objectClass":"MindNode","ID":"6R9ZF","children":{"0":{"objectClass":"MindNode","ID":"EY46I","text":"针对 DTO、枚举、工具类和异常处理等，在不同的微服务上下文中并不一定能完全复用，因此建议以复制代码的方式存在在不同的微服务中，且可以根据微服务自己的特点进行修正。"},"objectClass":"NSArray"},"text":"复制代码"},"2":{"objectClass":"MindNode","ID":"3YOUN","children":{"0":{"objectClass":"MindNode","ID":"TU9DH","text":"有时候还会在共享库中出现一些业务逻辑代码片段，一旦这样的共享发生，这是一个信号，很可能微服务之间的边界并不清楚，这时候要回来审视下微服务的划分是否合理或者微服务间的职责是否清晰。"},"objectClass":"NSArray"},"text":"不要共享业务逻辑代码片段"},"objectClass":"NSArray"},"